const cb = $input.first().json.callback_query;
const data = cb.data; // ready_123, go_123, book_123
const parts = data.split('_');
const action = parts[0]; // ready, go, book
const orderId = parts.slice(1).join('_');
const userId = String(cb.from.id);
const username = cb.from.username || '';
const firstName = cb.from.first_name || '';

// Фильтруем: нас интересуют только ready и go
if (!['ready', 'go', 'book'].includes(action)) {
  throw new Error('UNKNOWN_ACTION');
}

return [{
  json: {
    action,
    order_id: orderId,
    user_id: userId,
    username,
    first_name: firstName,
    callback_query_id: cb.id
  }
}];

const worker = $('Lookup Worker').first().json;
const userId = $('Parse Callback').first().json.user_id;

// Если исполнитель не найден в базе — автоматическая регистрация
if (!worker || !worker.telegram_id) {
  return [{
    json: {
      access: false,
      reason: 'NOT_REGISTERED',
      user_id: userId
    }
  }];
}

// Проверка бана
if (worker.ban_until) {
  const banDate = new Date(worker.ban_until);
  if (banDate > new Date()) {
    return [{
      json: {
        access: false,
        reason: 'BANNED',
        ban_until: worker.ban_until,
        user_id: userId
      }
    }];
  }
}

// Проверка white_list
if (worker.white_list !== 'TRUE' && worker.white_list !== true) {
  return [{
    json: {
      access: false,
      reason: 'NOT_WHITELISTED',
      user_id: userId
    }
  }];
}

// Проверка рейтинга
const rating = parseFloat(worker.rating) || 5.0;
if (rating < 4.0) {
  return [{
    json: {
      access: false,
      reason: 'LOW_RATING',
      rating,
      user_id: userId
    }
  }];
}

return [{
  json: {
    access: true,
    worker_id: worker.telegram_id,
    worker_name: worker.name || worker.username || 'Исполнитель',
    worker_phone: worker.phone || 'не указан',
    worker_rating: rating,
    worker_username: worker.username || '',
    is_vip: worker.is_vip === 'TRUE' || worker.is_vip === true
  }
}];

// Атомарная проверка — повторное чтение перед записью
const order = $('Lookup Order').first().json;
const worker = $('Check Access').first().json;

if (order.status !== 'published') {
  throw new Error('ORDER_ALREADY_TAKEN');
}

return [{
  json: {
    order_id: order.order_id,
    status: 'closed',
    executor_id: worker.worker_id,
    customer_id: order.customer_id,
    address: order.address,
    yandex_link: order.yandex_link,
    time: order.time,
    payment: order.payment,
    people: order.people,
    hours: order.hours,
    work_type: order.work_type,
    comment: order.comment,
    message_id: order.message_id,
    worker_name: worker.worker_name,
    worker_phone: worker.worker_phone,
    worker_rating: worker.worker_rating,
    worker_username: worker.worker_username
  }
}];

